const DESTINATIONS = [
  { id: 1, name: 'Kyoto, Japan', climate: 'temperate', budget: 'medium', rating: 4.8, reviews: 2341, img: '⛩️', tag: 'Culture', days: '5-7' },
  { id: 2, name: 'Bali, Indonesia', climate: 'tropical', budget: 'low', rating: 4.6, reviews: 3102, img: '🌴', tag: 'Beach', days: '7-10' },
  { id: 3, name: 'Reykjavik, Iceland', climate: 'cold', budget: 'high', rating: 4.7, reviews: 987, img: '🌋', tag: 'Adventure', days: '4-6' },
  { id: 4, name: 'Barcelona, Spain', climate: 'mediterranean', budget: 'medium', rating: 4.5, reviews: 4211, img: '🏖️', tag: 'City', days: '4-5' },
];

function SearchBar({ query, onChange }) {
  return (
    <div data-dg-component="searchBar" className="mx-4 mt-3">
      <div className="flex items-center bg-slate-100 rounded-2xl px-4 py-3 gap-2">
        <span className="text-slate-400">🔍</span>
        <input value={query} onChange={e => onChange(e.target.value)}
          placeholder="Search destinations..."
          className="flex-1 bg-transparent border-0 outline-none text-sm text-slate-700 placeholder:text-slate-400" />
        {query && <button onClick={() => onChange('')} className="text-slate-400 border-0 bg-transparent cursor-pointer text-sm">×</button>}
      </div>
    </div>
  );
}

function DestinationFilters({ climate, budget, onClimate, onBudget }) {
  return (
    <div data-dg-component="destinationFilters" className="flex gap-2 px-4 mt-3 overflow-x-auto pb-1" style={{ scrollbarWidth: 'none' }}>
      {['all', 'tropical', 'temperate', 'cold', 'mediterranean'].map(c => (
        <button key={c} onClick={() => onClimate(c)}
          className={`shrink-0 rounded-full px-3 py-1.5 text-xs font-semibold border-0 cursor-pointer ${climate === c ? 'bg-orange-500 text-white' : 'bg-slate-100 text-slate-500'}`}>
          {c === 'all' ? 'Any Climate' : c.charAt(0).toUpperCase() + c.slice(1)}
        </button>
      ))}
      <div className="w-px bg-slate-200 mx-1 shrink-0" />
      {['all', 'low', 'medium', 'high'].map(b => (
        <button key={b} onClick={() => onBudget(b)}
          className={`shrink-0 rounded-full px-3 py-1.5 text-xs font-semibold border-0 cursor-pointer ${budget === b ? 'bg-orange-500 text-white' : 'bg-slate-100 text-slate-500'}`}>
          {b === 'all' ? 'Any Budget' : b.charAt(0).toUpperCase() + b.slice(1)}
        </button>
      ))}
    </div>
  );
}

function DestinationDetail({ dest, onClose }) {
  if (!dest) return null;
  return (
    <div data-dg-component="destinationDetail" className="fixed inset-0 bg-black/50 flex items-end z-50" onClick={onClose}>
      <div className="bg-white rounded-t-3xl px-5 pt-6 pb-8 w-full max-w-[390px] mx-auto" onClick={e => e.stopPropagation()}>
        <div className="flex justify-between items-start mb-4">
          <div>
            <div className="text-2xl mb-1">{dest.img}</div>
            <div className="text-[18px] font-bold text-slate-900">{dest.name}</div>
            <div className="text-[13px] text-slate-400">⭐ {dest.rating} · {dest.reviews.toLocaleString()} reviews</div>
          </div>
          <button onClick={onClose} className="text-slate-400 text-2xl border-0 bg-transparent cursor-pointer">×</button>
        </div>
        <div className="grid grid-cols-3 gap-3 mb-4">
          {[['Climate', dest.climate], ['Budget', dest.budget], ['Best Stay', dest.days + ' days']].map(([l, v]) => (
            <div key={l} className="bg-slate-50 rounded-xl p-2.5 text-center">
              <div className="text-[10px] text-slate-400 uppercase tracking-widest">{l}</div>
              <div className="text-[13px] font-semibold text-slate-900 mt-0.5 capitalize">{v}</div>
            </div>
          ))}
        </div>
        <button onClick={onClose} className="w-full bg-orange-500 text-white rounded-xl py-3 text-[15px] font-bold border-0 cursor-pointer">
          Plan Trip →
        </button>
      </div>
    </div>
  );
}

function DestinationCards({ destinations, wishlist, onToggleWishlist, onSelect }) {
  return (
    <div data-dg-component="destinationCards" className="px-4 pt-3 pb-8">
      {destinations.length === 0 && (
        <div className="text-center py-10 text-slate-400">
          <div className="text-3xl mb-2">🌍</div>
          <div className="text-sm font-semibold">No destinations found</div>
        </div>
      )}
      {destinations.map(d => (
        <div key={d.id} onClick={() => onSelect(d)}
          className="bg-white rounded-2xl p-4 mb-3 shadow-sm cursor-pointer">
          <div className="flex justify-between items-start">
            <div className="flex items-center gap-3">
              <div className="text-[36px]">{d.img}</div>
              <div>
                <div className="text-[15px] font-bold text-slate-900">{d.name}</div>
                <div className="text-xs text-slate-400 mt-0.5">⭐ {d.rating} · {d.reviews.toLocaleString()} reviews</div>
              </div>
            </div>
            <button onClick={e => { e.stopPropagation(); onToggleWishlist(d.id); }}
              className={`border-0 bg-transparent text-xl cursor-pointer ${wishlist.includes(d.id) ? 'text-orange-500' : 'text-slate-300'}`}>
              🔖
            </button>
          </div>
          <div className="flex items-center gap-2 mt-3">
            <span className="rounded-full px-2.5 py-0.5 text-xs font-semibold bg-orange-50 text-orange-600">{d.tag}</span>
            <span className="rounded-full px-2.5 py-0.5 text-xs font-semibold bg-slate-100 text-slate-500 capitalize">{d.climate}</span>
            <span className="rounded-full px-2.5 py-0.5 text-xs font-semibold bg-slate-100 text-slate-500 capitalize">{d.budget} budget</span>
          </div>
        </div>
      ))}
    </div>
  );
}

function App() {
  const [query, setQuery] = React.useState('');
  const [climate, setClimate] = React.useState('all');
  const [budget, setBudget] = React.useState('all');
  const [wishlist, setWishlist] = React.useState([1]);
  const [selected, setSelected] = React.useState(null);

  const filtered = DESTINATIONS.filter(d => {
    const matchQ = d.name.toLowerCase().includes(query.toLowerCase());
    const matchC = climate === 'all' || d.climate === climate;
    const matchB = budget === 'all' || d.budget === budget;
    return matchQ && matchC && matchB;
  });

  const toggleWishlist = (id) => setWishlist(prev => prev.includes(id) ? prev.filter(w => w !== id) : [...prev, id]);

  return (
    <div className="min-h-screen bg-slate-50 font-sans max-w-[390px] mx-auto">
      <div className="bg-white px-5 pt-4 pb-3 border-b border-slate-100">
        <div className="text-[22px] font-bold text-slate-900">Discover</div>
        <div className="text-[13px] text-slate-400">Find your next destination</div>
      </div>
      <SearchBar query={query} onChange={setQuery} />
      <DestinationFilters climate={climate} budget={budget} onClimate={setClimate} onBudget={setBudget} />
      <DestinationCards destinations={filtered} wishlist={wishlist} onToggleWishlist={toggleWishlist} onSelect={setSelected} />
      <DestinationDetail dest={selected} onClose={() => setSelected(null)} />
    </div>
  );
}

const TRIP = { destination: 'Kyoto, Japan', dates: 'Apr 10 – Apr 16', travelers: 2 };

const HOTELS = [
  { id: 1, name: 'Nishiyama Ryokan', stars: 5, price: 280, area: 'Higashiyama', perks: ['Breakfast', 'Onsen'] },
  { id: 2, name: 'Sakura Garden Inn', stars: 4, price: 145, area: 'Gion', perks: ['Free WiFi', 'Garden'] },
  { id: 3, name: 'Kyoto Central Hotel', stars: 3, price: 89, area: 'Downtown', perks: ['Pool', 'Gym'] },
];

function TripHeader({ trip, onShare }) {
  return (
    <div data-dg-component="tripHeader" className="bg-white px-5 pt-4 pb-4 border-b border-slate-100">
      <div className="flex justify-between items-start">
        <div>
          <div className="text-[22px] font-bold text-slate-900">{trip.destination}</div>
          <div className="text-[13px] text-slate-400 mt-0.5">{trip.dates} · {trip.travelers} travelers</div>
        </div>
        <button onClick={onShare}
          className="bg-orange-50 text-orange-500 border-0 rounded-xl px-4 py-2 text-xs font-semibold cursor-pointer">
          Share
        </button>
      </div>
    </div>
  );
}

function ShareTrip({ show, onClose }) {
  if (!show) return null;
  return (
    <div data-dg-component="shareTrip" className="fixed inset-0 bg-black/40 flex items-end z-50" onClick={onClose}>
      <div className="bg-white rounded-t-3xl px-5 pt-6 pb-8 w-full max-w-[390px] mx-auto" onClick={e => e.stopPropagation()}>
        <div className="text-lg font-bold mb-4">Share Trip Plan</div>
        {[['Copy Link', '🔗'], ['Export PDF', '📄'], ['Notify Companions', '📧']].map(([label, icon]) => (
          <button key={label} onClick={onClose}
            className="w-full flex items-center gap-3 bg-slate-50 rounded-xl px-4 py-3 mb-2 border-0 cursor-pointer text-left">
            <span className="text-xl">{icon}</span>
            <span className="text-[14px] font-semibold text-slate-900">{label}</span>
          </button>
        ))}
      </div>
    </div>
  );
}

function ItineraryDay({ days, onAddActivity }) {
  return (
    <div data-dg-component="itineraryDay" className="mx-4 mt-4">
      <div className="text-[11px] font-bold text-slate-400 tracking-widest uppercase mb-2">Itinerary</div>
      {days.map(day => (
        <div key={day.day} className="bg-white rounded-2xl p-4 mb-3 shadow-sm">
          <div className="flex justify-between items-center mb-2">
            <div className="text-[14px] font-bold text-slate-900">{day.day}</div>
            <button onClick={() => onAddActivity(day.day)}
              className="text-orange-500 text-xs font-semibold border-0 bg-transparent cursor-pointer">+ Add</button>
          </div>
          {day.activities.map((a, i) => (
            <div key={i} className="flex items-center gap-2 py-1.5 border-b border-slate-50 last:border-0">
              <span className="text-base">{a.icon}</span>
              <span className="text-[13px] text-slate-700">{a.name}</span>
              <span className="ml-auto text-[11px] text-slate-400">{a.time}</span>
            </div>
          ))}
        </div>
      ))}
    </div>
  );
}

function HotelCard({ hotels, selected, onSelect }) {
  return (
    <div data-dg-component="hotelCard" className="mx-4 mt-4">
      <div className="text-[11px] font-bold text-slate-400 tracking-widest uppercase mb-2">Hotels</div>
      {hotels.map(h => (
        <div key={h.id} onClick={() => onSelect(h.id)}
          className={`bg-white rounded-2xl p-4 mb-2.5 shadow-sm cursor-pointer ${selected === h.id ? 'ring-2 ring-orange-500' : ''}`}>
          <div className="flex justify-between items-start">
            <div>
              <div className="text-[14px] font-bold text-slate-900">{h.name}</div>
              <div className="text-xs text-slate-400 mt-0.5">{'⭐'.repeat(h.stars)} · {h.area}</div>
            </div>
            <div className="text-right">
              <div className="text-[16px] font-bold text-slate-900">${h.price}</div>
              <div className="text-[11px] text-slate-400">/ night</div>
            </div>
          </div>
          <div className="flex gap-1.5 mt-2">
            {h.perks.map(p => (
              <span key={p} className="text-[11px] bg-slate-100 text-slate-500 rounded-full px-2 py-0.5">{p}</span>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
}

function BudgetSummary({ items }) {
  const total = items.reduce((s, i) => s + i.amount, 0);
  const budget = 1500;
  return (
    <div data-dg-component="budgetSummary" className="mx-4 mt-4 bg-white rounded-2xl p-5 shadow-sm">
      <div className="flex justify-between items-center mb-3">
        <div className="text-[15px] font-bold text-slate-900">Budget</div>
        <div className={`text-[13px] font-semibold ${total > budget ? 'text-red-500' : 'text-emerald-500'}`}>
          ${total} / ${budget}
        </div>
      </div>
      <div className="h-2 bg-slate-100 rounded-full overflow-hidden mb-3">
        <div className={`h-full rounded-full ${total > budget ? 'bg-red-500' : 'bg-emerald-500'}`} style={{ width: `${Math.min((total / budget) * 100, 100)}%` }} />
      </div>
    </div>
  );
}

function ExpenseItem({ items, onAdd }) {
  const [show, setShow] = React.useState(false);
  return (
    <div data-dg-component="expenseItem" className="mx-4 mt-2 mb-8">
      <div className="flex justify-between items-center mb-2">
        <div className="text-[11px] font-bold text-slate-400 tracking-widest uppercase">Expenses</div>
        <button onClick={() => setShow(s => !s)}
          className="text-xs text-orange-500 font-semibold border-0 bg-transparent cursor-pointer">
          {show ? '− Less' : '+ Add'}
        </button>
      </div>
      {show && (
        <div className="bg-white rounded-xl p-3 mb-2 shadow-sm">
          {[['Flights', '✈️', 480], ['Accommodation', '🏨', 420], ['Activities', '🎭', 180]].map(([label, icon, amt]) => (
            <button key={label} onClick={() => onAdd({ label, amount: amt })}
              className="w-full flex items-center gap-2 py-2 border-0 bg-transparent cursor-pointer text-left border-b border-slate-50 last:border-0">
              <span>{icon}</span>
              <span className="text-[13px] text-slate-700 flex-1">{label}</span>
              <span className="text-[13px] font-semibold text-slate-900">${amt}</span>
            </button>
          ))}
        </div>
      )}
      {items.map((item, i) => (
        <div key={i} className="bg-white rounded-xl p-3 mb-1.5 shadow-sm flex items-center gap-2">
          <span className="text-[15px]">💰</span>
          <span className="text-[13px] text-slate-700 flex-1">{item.label}</span>
          <span className="text-[13px] font-bold text-slate-900">${item.amount}</span>
        </div>
      ))}
    </div>
  );
}

function App() {
  const [showShare, setShowShare] = React.useState(false);
  const [selectedHotel, setSelectedHotel] = React.useState(2);
  const [expenses, setExpenses] = React.useState([
    { label: 'Flights', amount: 480 },
    { label: 'Accommodation', amount: 420 },
  ]);

  const itineraryDays = [
    { day: 'Apr 10', activities: [{ icon: '✈️', name: 'Arrive Kansai Airport', time: '2:00 PM' }, { icon: '🏨', name: 'Check in Ryokan', time: '4:30 PM' }] },
    { day: 'Apr 11', activities: [{ icon: '⛩️', name: 'Fushimi Inari', time: '9:00 AM' }, { icon: '🎎', name: 'Gion Walk', time: '3:00 PM' }] },
    { day: 'Apr 12', activities: [{ icon: '🌸', name: 'Arashiyama Bamboo', time: '8:30 AM' }] },
  ];

  const addActivity = (day) => {
    // no-op placeholder
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans max-w-[390px] mx-auto">
      <TripHeader trip={TRIP} onShare={() => setShowShare(true)} />
      <ShareTrip show={showShare} onClose={() => setShowShare(false)} />
      <ItineraryDay days={itineraryDays} onAddActivity={addActivity} />
      <HotelCard hotels={HOTELS} selected={selectedHotel} onSelect={setSelectedHotel} />
      <BudgetSummary items={expenses} />
      <ExpenseItem items={expenses} onAdd={(item) => setExpenses(prev => [...prev, item])} />
    </div>
  );
}
